use std::env;
use std::fs;
use std::path::{Path, PathBuf};

fn collect_modules(root: &Path, dir: &Path, modules: &mut Vec<(String, PathBuf)>) {
    let mut entries = fs::read_dir(dir)
        .unwrap_or_else(|error| panic!("failed to read {}: {error}", dir.display()))
        .collect::<Result<Vec<_>, _>>()
        .unwrap_or_else(|error| panic!("failed to enumerate {}: {error}", dir.display()));
    entries.sort_by_key(|entry| entry.path());

    for entry in entries {
        let path = entry.path();
        if path.is_dir() {
            collect_modules(root, &path, modules);
        } else if path.extension().and_then(|ext| ext.to_str()) == Some("mjs") {
            let relative = path
                .strip_prefix(root)
                .expect("module must be under js/")
                .to_string_lossy()
                .replace('\\', "/");
            modules.push((format!("/qjs/{relative}"), path));
        }
    }
}

fn generate_module_table(manifest_dir: &Path, out_dir: &Path) {
    let js_root = manifest_dir.join("js");
    let mut modules = Vec::new();
    collect_modules(&js_root, &js_root, &mut modules);

    let mut generated = String::from("// @generated by build.rs\n");
    generated.push_str("static EMBEDDED_MODULES: &[EmbeddedModule] = &[\n");
    for (specifier, path) in modules {
        println!("cargo:rerun-if-changed={}", path.display());
        let path = path
            .to_string_lossy()
            .replace('\\', "\\\\")
            .replace('"', "\\\"");
        generated.push_str("    EmbeddedModule {\n");
        generated.push_str(&format!("        specifier: {:?},\n", specifier));
        generated.push_str(&format!("        source: include_bytes!(\"{path}\"),\n"));
        generated.push_str("    },\n");
    }
    generated.push_str("];\n");

    fs::write(out_dir.join("embedded_modules.rs"), generated)
        .expect("failed to generate embedded_modules.rs");
}

fn build_quickjs(manifest_dir: &Path) {
    let quickjs = manifest_dir.join("vendor/quickjs");
    let version = fs::read_to_string(quickjs.join("VERSION"))
        .expect("vendor/quickjs/VERSION is missing")
        .trim()
        .to_owned();

    for file in [
        "quickjs.c",
        "quickjs.h",
        "quickjs-atom.h",
        "quickjs-opcode.h",
        "libregexp.c",
        "libregexp.h",
        "libregexp-opcode.h",
        "libunicode.c",
        "libunicode.h",
        "libunicode-table.h",
        "cutils.c",
        "cutils.h",
        "dtoa.c",
        "dtoa.h",
        "list.h",
    ] {
        println!("cargo:rerun-if-changed={}", quickjs.join(file).display());
    }
    println!("cargo:rerun-if-changed=src/quickjs_shim.c");

    let mut build = cc::Build::new();
    build
        .include(&quickjs)
        .file(quickjs.join("quickjs.c"))
        .file(quickjs.join("libregexp.c"))
        .file(quickjs.join("libunicode.c"))
        .file(quickjs.join("cutils.c"))
        .file(quickjs.join("dtoa.c"))
        .file(manifest_dir.join("src/quickjs_shim.c"))
        .define("_GNU_SOURCE", None)
        .define("CONFIG_VERSION", Some(format!("\"{version}\"").as_str()))
        .warnings(false)
        .compile("rust_qjs_dom_quickjs");

    if env::var("CARGO_CFG_UNIX").is_ok() {
        println!("cargo:rustc-link-lib=m");
        println!("cargo:rustc-link-lib=pthread");
    }
}

fn main() {
    let manifest_dir = PathBuf::from(env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR"));
    let out_dir = PathBuf::from(env::var("OUT_DIR").expect("OUT_DIR"));
    println!("cargo:rerun-if-changed=js");
    generate_module_table(&manifest_dir, &out_dir);
    build_quickjs(&manifest_dir);
}
